//=============================================================================
// AutoDetectEndFace: vote-based end face detection
//   Find the planar face perpendicular to the most cylindrical faces.
//=============================================================================
void FeatureSpy260714::AutoDetectEndFace()
{
	if (pFaceList.size() == 0) return;

	std::vector<NXOpen::Vector3d> cylAxes;
	for (size_t i = 0; i < pFaceList.size(); i++)
	{
		NXOpen::Face* F = pFaceList[i];
		if (F->SolidFaceType() == NXOpen::Face::FaceTypeCylindrical)
		{
			int type=0, norm_dir=0;
			double point[3], dir[3], box[6], radius, rad_data;
			UF_MODL_ask_face_data(F->Tag(), &type, point, dir, box, &radius, &rad_data, &norm_dir);
			cylAxes.push_back(NXOpen::Vector3d(dir[0], dir[1], dir[2]));
		}
	}

	if (cylAxes.size() == 0) { _Approach_Normal = NXOpen::Vector3d(0,0,1); Begin_Face = NULL; return; }

	std::vector<NXOpen::Face*> planarFaces;
	std::vector<NXOpen::Vector3d> planarNormals;
	for (size_t i = 0; i < pFaceList.size(); i++)
	{
		NXOpen::Face* F = pFaceList[i];
		if (F->SolidFaceType() == NXOpen::Face::FaceTypePlanar)
		{
			NXOpen::Vector3d N;
			get_MainNormal_fr_plane(F, N);
			planarFaces.push_back(F);
			planarNormals.push_back(N);
		}
	}

	if (planarFaces.size() == 0) { _Approach_Normal = NXOpen::Vector3d(0,0,1); Begin_Face = NULL; return; }

	int bestIdx = 0, bestCount = 0;
	for (size_t pi = 0; pi < planarFaces.size(); pi++)
	{
		int count = 0;
		for (size_t ci = 0; ci < cylAxes.size(); ci++)
		{
			double ang = get_Angle_Two_vector3d(planarNormals[pi], cylAxes[ci]);
			ang = ang / 3.14159265358979323846 * 180.0;
			if (ang < 1.0 || ang > 179.0) count++;
		}
		if (count > bestCount) { bestCount = count; bestIdx = (int)pi; }
	}

	Begin_Face = planarFaces[bestIdx];
	_Approach_Normal = planarNormals[bestIdx];
	DefaultColor = 186;
}

